import type { HTMLAttributes, ReactNode } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
import type { AvatarProps } from '../Avatar/Avatar.types';
import type { InformerProps } from '../Informer/Informer.types';
/**
 * Размеры компонента AvatarText.
 * - default — стандартный размер (Avatar medium, отступ 12px)
 * - mini — компактный размер (Avatar small, отступ 8px)
 */
export type AvatarTextSize = 'default' | 'mini';
/**
 * Пропсы для настройки Informer (бейджа на аватаре).
 * Если передан, Avatar будет обернут в Informer.
 * Размер Informer устанавливается автоматически в зависимости от size компонента:
 * - default → Informer size: 'large'
 * - mini → Informer size: 'medium'
 */
export interface AvatarTextInformerProps extends Pick<InformerProps, 'content' | 'semantic' | 'className'> {
    /**
     * Размер информера.
     * Если не указан, устанавливается автоматически в зависимости от size компонента.
     */
    size?: InformerProps['size'];
}
/**
 * Пропсы для настройки Avatar.
 * Размер Avatar устанавливается автоматически в зависимости от size компонента:
 * - default → Avatar size: 'medium'
 * - mini → Avatar size: 'small'
 */
export interface AvatarTextAvatarProps extends Omit<AvatarProps, 'size'> {
}
/**
 * Публичные пропсы компонента AvatarText.
 *
 * Компонент отображает аватар (опционально с бейджем через Informer),
 * основной текст (Typography body2), вторичный текст (Typography body3)
 * и опциональный суффикс.
 *
 * Текст автоматически обрезается при недостатке места.
 *
 * @example
 * ```tsx
 * <AvatarText
 *   size="default"
 *   avatarProps={{ src: "/avatar.jpg" }}
 *   label="Юлия Соломатина"
 *   description="Менеджер"
 *   informerProps={{ content: 2, semantic: 'danger' }}
 * />
 * ```
 */
export interface AvatarTextProps extends TestComponentProps, Omit<HTMLAttributes<HTMLDivElement>, 'children' | 'ref'> {
    /**
     * Размер компонента.
     * @default 'default'
     */
    size?: AvatarTextSize;
    /**
     * Пропсы для настройки Avatar.
     * Размер Avatar устанавливается автоматически в зависимости от size компонента.
     */
    avatarProps: AvatarTextAvatarProps;
    /**
     * Пропсы для настройки Informer (бейджа на аватаре).
     * Если передан, Avatar будет обернут в Informer.
     * Размер Informer устанавливается автоматически в зависимости от size компонента.
     */
    informerProps?: AvatarTextInformerProps;
    /**
     * Основной текст (отображается через Typography body2).
     * Обязательное поле. Автоматически обрезается при недостатке места.
     */
    label: string;
    /**
     * Вторичный текст (отображается через Typography body3).
     * Опциональное поле. Автоматически обрезается при недостатке места.
     */
    description?: string;
    /**
     * Кастомный суффикс компонента.
     * Отображается справа от текстовых блоков.
     * Если передан string, будет отображен через Typography body3 зеленого цвета (status success).
     */
    suffix?: ReactNode | string;
    /**
     * Пользовательский класс.
     */
    className?: string;
    /**
     * Идентификатор для тестов.
     * @default 'AvatarText'
     */
    dataTestId?: string;
}
